selector_to_html = {"a[href=\"#id3\"]": "<figure class=\"align-center\" id=\"id3\">\n<a class=\"reference internal image-reference\" href=\"../../media/25WFCOMMPM23S1.png\"><img alt=\"../../media/25WFCOMMPM23S1.png\" src=\"../../media/25WFCOMMPM23S1.png\" style=\"width: 300px;\"/>\n</a>\n<figcaption>\n<p><span class=\"caption-text\">Json Format</span><a class=\"headerlink\" href=\"#id3\" title=\"Link to this image\">#</a></p>\n</figcaption>\n</figure>", "a[href=\"#configure-wifi-and-api-url-address\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0643\u0648\u064a\u0646 \u0639\u0646\u0648\u0627\u0646 URL \u0644\u0644\u0648\u0627\u064a \u0641\u0627\u064a \u0648 API<a class=\"headerlink\" href=\"#configure-wifi-and-api-url-address\" title=\"Link to this heading\">#</a></h3>", "a[href=\"wireless.html#data-rceiving-format\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0646\u0633\u064a\u0642 \u062a\u0635\u0648\u064a\u0631 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a<a class=\"headerlink\" href=\"#data-rceiving-format\" title=\"Link to this heading\">#</a></h2><h3>\u0627\u0644\u0631\u0645\u0632 \u0627\u0644\u0635\u0648\u062a\u064a<a class=\"headerlink\" href=\"#voice-code\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#id1\"]": "<div class=\"literal-block-wrapper docutils container\" id=\"id1\">\n<div class=\"code-block-caption\"><span class=\"caption-text\">\u0637\u0644\u0628 \u0645\u062b\u0627\u0644</span><a class=\"headerlink\" href=\"#id1\" title=\"Link to this code\">#</a></div>\n<div class=\"highlight-json notranslate\"><div class=\"highlight\"><pre><span></span><span class=\"linenos\">1</span><span class=\"p\">{</span><span class=\"nt\">\"id\"</span><span class=\"p\">:</span><span class=\"w\"> </span><span class=\"s2\">\"04B9023A\"</span><span class=\"p\">,</span><span class=\"nt\">\"msg\"</span><span class=\"p\">:</span><span class=\"s2\">\"1234567890\"</span><span class=\"p\">}</span>\n</pre></div>\n</div>\n</div>", "a[href=\"#id2\"]": "<figure class=\"align-center\" id=\"id2\">\n<a class=\"reference internal image-reference\" href=\"../../media/application-json.png\"><img alt=\"../../media/application-json.png\" src=\"../../media/application-json.png\" style=\"width: 300px;\"/>\n</a>\n<figcaption>\n<p><span class=\"caption-text\">\u062a\u0637\u0628\u064a\u0642/\u062c\u0633\u0648\u0646</span><a class=\"headerlink\" href=\"#id2\" title=\"Link to this image\">#</a></p>\n</figcaption>\n</figure>", "a[href=\"#set-the-content-type-of-the-scanner-request\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0639\u064a\u064a\u0646 \u0646\u0648\u0639 \u0627\u0644\u0645\u062d\u062a\u0648\u0649 \u0645\u0646 \u0637\u0644\u0628 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a<a class=\"headerlink\" href=\"#set-the-content-type-of-the-scanner-request\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#request-parameters\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u0637\u0644\u0628 \u0645\u0639\u0644\u0645\u0627\u062a<a class=\"headerlink\" href=\"#request-parameters\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#brief-description\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0635\u0641 \u0645\u0648\u062c\u0632<a class=\"headerlink\" href=\"#brief-description\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#create-rest-api\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0646\u0634\u0627\u0621 REST API<a class=\"headerlink\" href=\"#create-rest-api\" title=\"Link to this heading\">#</a></h2><h3>\u0648\u0635\u0641 \u0645\u0648\u062c\u0632<a class=\"headerlink\" href=\"#brief-description\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#request-mode\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0636\u0639 \u0627\u0644\u0637\u0644\u0628<a class=\"headerlink\" href=\"#request-mode\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#return-parameter\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u0645\u0639\u0644\u0645\u0629 \u0627\u0644\u0625\u0631\u062c\u0627\u0639<a class=\"headerlink\" href=\"#return-parameter\" title=\"Link to this heading\">#</a></h3><p>\u0644\u0644\u062d\u0635\u0648\u0644 \u0639\u0644\u0649 \u0627\u0644\u062a\u0641\u0627\u0635\u064a\u0644\u060c \u0627\u0646\u0638\u0631 <a class=\"reference internal\" href=\"wireless.html#data-rceiving-format\"><span class=\"std std-ref\">\u062a\u0646\u0633\u064a\u0642 \u062a\u0644\u0642\u064a \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a</span></a></p>", "a[href=\"#request-url\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u0637\u0644\u0628 \u0639\u0646\u0648\u0627\u0646 URL<a class=\"headerlink\" href=\"#request-url\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#use-http-protocol-to-transfer-data\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0628\u0631\u0648\u062a\u0648\u0643\u0648\u0644 HTTP \u0644\u0646\u0642\u0644 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a<a class=\"headerlink\" href=\"#use-http-protocol-to-transfer-data\" title=\"Link to this heading\">#</a></h1><h2>\u0625\u0646\u0634\u0627\u0621 REST API<a class=\"headerlink\" href=\"#create-rest-api\" title=\"Link to this heading\">#</a></h2><h3>\u0648\u0635\u0641 \u0645\u0648\u062c\u0632<a class=\"headerlink\" href=\"#brief-description\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#set-the-data-format-sent-by-the-scanner\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0639\u064a\u064a\u0646 \u062a\u0646\u0633\u064a\u0642 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u0645\u0631\u0633\u0644\u0629 \u0645\u0646 \u0642\u0628\u0644 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a<a class=\"headerlink\" href=\"#set-the-data-format-sent-by-the-scanner\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#configure-scanner\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0643\u0648\u064a\u0646 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a<a class=\"headerlink\" href=\"#configure-scanner\" title=\"Link to this heading\">#</a></h2><h3>\u062a\u0639\u064a\u064a\u0646 \u0646\u0648\u0639 \u0627\u0644\u0645\u062d\u062a\u0648\u0649 \u0645\u0646 \u0637\u0644\u0628 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a<a class=\"headerlink\" href=\"#set-the-content-type-of-the-scanner-request\" title=\"Link to this heading\">#</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link", "sd-rounded-pill"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
